23	#ifndef MUPDF_PDF_XREF_H
24	#define MUPDF_PDF_XREF_H
25	
26	#include "mupdf/pdf/document.h"
27	
28	/*
29		Allocate a slot in the xref table and return a fresh unused object number.
30	*/
31	int pdf_create_object(fz_context *ctx, pdf_document *doc);
32	
33	/*
34		Remove object from xref table, marking the slot as free.
35	*/
36	void pdf_delete_object(fz_context *ctx, pdf_document *doc, int num);
37	
38	/*
39		Replace object in xref table with the passed in object.
40	*/
41	void pdf_update_object(fz_context *ctx, pdf_document *doc, int num, pdf_obj *obj);
42	
43	/*
44		Replace stream contents for object in xref table with the passed in buffer.
45	
46		The buffer contents must match the /Filter setting if 'compressed' is true.
47		If 'compressed' is false, the /Filter and /DecodeParms entries are deleted.
48		The /Length entry is updated.
49	*/
50	void pdf_update_stream(fz_context *ctx, pdf_document *doc, pdf_obj *ref, fz_buffer *buf, int compressed);
51	
52	/*
53		Return true if 'obj' is an indirect reference to an object that is held
54		by the "local" xref section.
55	*/
56	int pdf_is_local_object(fz_context *ctx, pdf_document *doc, pdf_obj *obj);
57	
58	pdf_obj *pdf_add_object(fz_context *ctx, pdf_document *doc, pdf_obj *obj);
59	pdf_obj *pdf_add_object_drop(fz_context *ctx, pdf_document *doc, pdf_obj *obj);
60	pdf_obj *pdf_add_stream(fz_context *ctx, pdf_document *doc, fz_buffer *buf, pdf_obj *obj, int compressed);
61	
62	pdf_obj *pdf_add_new_dict(fz_context *ctx, pdf_document *doc, int initial);
63	pdf_obj *pdf_add_new_array(fz_context *ctx, pdf_document *doc, int initial);
64	
65	typedef struct
66	{
67		char type;		/* 0=unset (f)ree i(n)use (o)bjstm */
68		unsigned char marked;	/* marked to keep alive with pdf_mark_xref */
69		unsigned short gen;	/* generation / objstm index */
70		int num;		/* original object number (for decryption after renumbering) */
71		int64_t ofs;		/* file offset / objstm object number */
72		int64_t stm_ofs;	/* on-disk stream */
73		fz_buffer *stm_buf;	/* in-memory stream (for updated objects) */
74		pdf_obj *obj;		/* stored/cached object */
75	} pdf_xref_entry;
76	
77	typedef struct pdf_xref_subsec
78	{
79		struct pdf_xref_subsec *next;
80		int len;
81		int start;
82		pdf_xref_entry *table;
83	} pdf_xref_subsec;
84	
85	struct pdf_xref
86	{
87		int num_objects;
88		int num_subsecs;
89		pdf_xref_subsec *subsec;
90		pdf_obj *trailer;
91		pdf_obj *pre_repair_trailer;
92		pdf_unsaved_sig *unsaved_sigs;
93		pdf_unsaved_sig **unsaved_sigs_end;
94		int64_t end_ofs; /* file offset to end of xref */
95	};
96	
97	/**
98		Retrieve the pdf_xref_entry for a given object.
99	
100		This can cause xref reorganisations (solidifications etc) due to
101		repairs, so all held pdf_xref_entries should be considered
102		invalid after this call (other than the returned one).
103	*/
104	pdf_xref_entry *pdf_cache_object(fz_context *ctx, pdf_document *doc, int num);
105	
106	int pdf_object_exists(fz_context *ctx, pdf_document *doc, int num);
107	
108	int pdf_count_objects(fz_context *ctx, pdf_document *doc);
109	
110	/**
111		Resolve an indirect object (or chain of objects).
112	
113		This can cause xref reorganisations (solidifications etc) due to
114		repairs, so all held pdf_xref_entries should be considered
115		invalid after this call (other than the returned one).
116	*/
117	pdf_obj *pdf_resolve_indirect(fz_context *ctx, pdf_obj *ref);
118	pdf_obj *pdf_resolve_indirect_chain(fz_context *ctx, pdf_obj *ref);
119	
120	/**
121		Load a given object.
122	
123		This can cause xref reorganisations (solidifications etc) due to
124		repairs, so all held pdf_xref_entries should be considered
125		invalid after this call (other than the returned one).
126	*/
127	pdf_obj *pdf_load_object(fz_context *ctx, pdf_document *doc, int num);
128	pdf_obj *pdf_load_unencrypted_object(fz_context *ctx, pdf_document *doc, int num);
129	
130	/*
131		Load raw (compressed but decrypted) contents of a stream into buf.
132	*/
133	fz_buffer *pdf_load_raw_stream_number(fz_context *ctx, pdf_document *doc, int num);
134	fz_buffer *pdf_load_raw_stream(fz_context *ctx, pdf_obj *ref);
135	
136	/*
137		Load uncompressed contents of a stream into buf.
138	*/
139	fz_buffer *pdf_load_stream_number(fz_context *ctx, pdf_document *doc, int num);
140	fz_buffer *pdf_load_stream(fz_context *ctx, pdf_obj *ref);
141	
142	/*
143		Open a stream for reading the raw (compressed but decrypted) data.
144	*/
145	fz_stream *pdf_open_raw_stream_number(fz_context *ctx, pdf_document *doc, int num);
146	fz_stream *pdf_open_raw_stream(fz_context *ctx, pdf_obj *ref);
147	
148	/*
149		Open a stream for reading uncompressed data.
150		Put the opened file in doc->stream.
151		Using doc->file while a stream is open is a Bad idea.
152	*/
153	fz_stream *pdf_open_stream_number(fz_context *ctx, pdf_document *doc, int num);
154	fz_stream *pdf_open_stream(fz_context *ctx, pdf_obj *ref);
155	
156	/*
157		Construct a filter to decode a stream, without
158		constraining to stream length, and without decryption.
159	*/
160	fz_stream *pdf_open_inline_stream(fz_context *ctx, pdf_document *doc, pdf_obj *stmobj, size_t length, fz_stream *chain, fz_compression_params *params);
161	fz_compressed_buffer *pdf_load_compressed_stream(fz_context *ctx, pdf_document *doc, int num, size_t worst_case);
162	void pdf_load_compressed_inline_image(fz_context *ctx, pdf_document *doc, pdf_obj *dict, size_t length, fz_stream *cstm, int indexed, fz_compressed_image *image);
163	fz_stream *pdf_open_stream_with_offset(fz_context *ctx, pdf_document *doc, int num, pdf_obj *dict, int64_t stm_ofs);
164	fz_stream *pdf_open_contents_stream(fz_context *ctx, pdf_document *doc, pdf_obj *obj);
165	fz_buffer *pdf_load_image_stream(fz_context *ctx, pdf_document *doc, int num, fz_compression_params *params, int *truncated, size_t worst_case);
166	
167	int pdf_version(fz_context *ctx, pdf_document *doc);
168	pdf_obj *pdf_trailer(fz_context *ctx, pdf_document *doc);
169	void pdf_set_trailer(fz_context *ctx, pdf_document *doc, pdf_obj *obj);
170	void pdf_set_populating_xref_trailer(fz_context *ctx, pdf_document *doc, pdf_obj *trailer);
171	int pdf_xref_len(fz_context *ctx, pdf_document *doc);
172	
173	pdf_obj *pdf_metadata(fz_context *ctx, pdf_document *doc);
174	
175	/*
176		Used while reading the individual xref sections from a file.
177	*/
178	pdf_xref_entry *pdf_get_populating_xref_entry(fz_context *ctx, pdf_document *doc, int i);
179	
180	/*
181		Used after loading a document to access entries.
182	
183		This will never throw anything, or return NULL if it is
184		only asked to return objects in range within a 'solid'
185		xref.
186	
187		This may "solidify" the xref (so can cause allocations).
188	*/
189	pdf_xref_entry *pdf_get_xref_entry(fz_context *ctx, pdf_document *doc, int i);
190	
191	/*
192		Map a function across all xref entries in a document.
193	*/
194	void pdf_xref_entry_map(fz_context *ctx, pdf_document *doc, void (*fn)(fz_context *, pdf_xref_entry *, int i, pdf_document *doc, void *), void *arg);
195	
196	
197	/*
198		Used after loading a document to access entries.
199	
200		This will never throw anything, or return NULL if it is
201		only asked to return objects in range within a 'solid'
202		xref.
203	
204		This will never "solidify" the xref, so no entry may be found
205		(NULL will be returned) for free entries.
206	
207		Called with a valid i, this will never try/catch or throw.
208	*/
209	pdf_xref_entry *pdf_get_xref_entry_no_change(fz_context *ctx, pdf_document *doc, int i);
210	pdf_xref_entry *pdf_get_xref_entry_no_null(fz_context *ctx, pdf_document *doc, int i);
211	void pdf_replace_xref(fz_context *ctx, pdf_document *doc, pdf_xref_entry *entries, int n);
212	void pdf_forget_xref(fz_context *ctx, pdf_document *doc);
213	pdf_xref_entry *pdf_get_incremental_xref_entry(fz_context *ctx, pdf_document *doc, int i);
214	
215	/*
216		Ensure that an object has been cloned into the incremental xref section.
217	*/
218	int pdf_xref_ensure_incremental_object(fz_context *ctx, pdf_document *doc, int num);
219	int pdf_xref_is_incremental(fz_context *ctx, pdf_document *doc, int num);
220	void pdf_xref_store_unsaved_signature(fz_context *ctx, pdf_document *doc, pdf_obj *field, pdf_pkcs7_signer *signer);
221	void pdf_xref_remove_unsaved_signature(fz_context *ctx, pdf_document *doc, pdf_obj *field);
222	int pdf_xref_obj_is_unsaved_signature(pdf_document *doc, pdf_obj *obj);
223	void pdf_xref_ensure_local_object(fz_context *ctx, pdf_document *doc, int num);
224	int pdf_obj_is_incremental(fz_context *ctx, pdf_obj *obj);
225	
226	void pdf_repair_xref(fz_context *ctx, pdf_document *doc);
227	
228	/*
229		Ensure that the current populating xref has a single subsection
230		that covers the entire range.
231	*/
232	void pdf_ensure_solid_xref(fz_context *ctx, pdf_document *doc, int num);
233	void pdf_mark_xref(fz_context *ctx, pdf_document *doc);
234	void pdf_clear_xref(fz_context *ctx, pdf_document *doc);
235	void pdf_clear_xref_to_mark(fz_context *ctx, pdf_document *doc);
236	
237	int pdf_repair_obj(fz_context *ctx, pdf_document *doc, pdf_lexbuf *buf, int64_t *stmofsp, int64_t *stmlenp, pdf_obj **encrypt, pdf_obj **id, pdf_obj **page, int64_t *tmpofs, pdf_obj **root);
238	
239	pdf_obj *pdf_progressive_advance(fz_context *ctx, pdf_document *doc, int pagenum);
240	
241	/*
242		Return the number of versions that there
243		are in a file. i.e. 1 + the number of updates that
244		the file on disc has been through. i.e. internal
245		unsaved changes to the file (such as appearance streams)
246		are ignored. Also, the initial write of a linearized
247		file (which appears as a base file write + an incremental
248		update) is treated as a single version.
249	*/
250	int pdf_count_versions(fz_context *ctx, pdf_document *doc);
251	int pdf_count_unsaved_versions(fz_context *ctx, pdf_document *doc);
252	int pdf_validate_changes(fz_context *ctx, pdf_document *doc, int version);
253	int pdf_doc_was_linearized(fz_context *ctx, pdf_document *doc);
254	
255	typedef struct pdf_locked_fields pdf_locked_fields;
256	int pdf_is_field_locked(fz_context *ctx, pdf_locked_fields *locked, const char *name);
257	void pdf_drop_locked_fields(fz_context *ctx, pdf_locked_fields *locked);
258	pdf_locked_fields *pdf_find_locked_fields(fz_context *ctx, pdf_document *doc, int version);
259	pdf_locked_fields *pdf_find_locked_fields_for_sig(fz_context *ctx, pdf_document *doc, pdf_obj *sig);
260	
261	/*
262		Check the entire history of the document, and return the number of
263		the last version that checked out OK.
264		i.e. 0 = "the entire history checks out OK".
265			  n = "none of the history checked out OK".
266	*/
267	int pdf_validate_change_history(fz_context *ctx, pdf_document *doc);
268	
269	/*
270		Find which version of a document the current version of obj
271		was defined in.
272	
273		version = 0 = latest, 1 = previous update etc, allowing for
274		the first incremental update in a linearized file being ignored.
275	*/
276	int pdf_find_version_for_obj(fz_context *ctx, pdf_document *doc, pdf_obj *obj);
277	
278	/*
279		Return the number of updates ago when a signature field
280		became invalid, not counting any unsaved changes.
281	
282		Thus:
283		 -1 => Has changed in the current unsaved changes.
284		  0 => still valid.
285		  1 => became invalid on the last save
286		  n => became invalid n saves ago
287	*/
288	int pdf_validate_signature(fz_context *ctx, pdf_document *doc, pdf_obj *field);
289	int pdf_validate_signature_widget(fz_context *ctx, pdf_annot *widget);
290	int pdf_was_pure_xfa(fz_context *ctx, pdf_document *doc);
291	
292	/* Local xrefs - designed for holding stuff that shouldn't be written
293	 * back into the actual document, such as synthesized appearance
294	 * streams. */
295	pdf_xref *pdf_new_local_xref(fz_context *ctx, pdf_document *doc);
296	
297	void pdf_drop_local_xref(fz_context *ctx, pdf_xref *xref);
298	void pdf_drop_local_xref_and_resources(fz_context *ctx, pdf_document *doc);
299	
300	/* Debug call to dump the incremental/local xrefs to the
301	 * debug channel. */
302	void pdf_debug_doc_changes(fz_context *ctx, pdf_document *doc);
303	
304	#endif
